func main() {
	// Parse command line arguments
	flag.Parse()
	flag.Usage = usage
	if flag.NArg() < 1 {
		usage()
		os.Exit(1)
	}

	// Get the input file path
	inputFile := flag.Arg(0)
	outputFile := flag.Arg(1)

	// Read input
	input, err := os.ReadFile(inputFile)
	if err != nil {
		log.Fatalf("Error reading input file: %v", err)
	}

	// Parse the input
	start := time.Now()
	tree := Parse(string(input), inputFile)
	elapsed := time.Since(start)

	// Output the result
	if outputFile != "" {
		f, err := os.Create(outputFile)
		if err != nil {
			log.Fatalf("Error creating output file: %v", err)
		}
		defer f.Close()
		w := bufio.NewWriter(f)
		defer w.Flush()
		fmt.Fprintf(w, "%s\n", tree)
	} else {
		fmt.Println(tree)
	}

	// Print statistics
	if *statsFlag {
		printStats(input, elapsed)
	}
}

var (
	flag     = flag.NewFlagSet(os.Args[0], flag.ExitOnError)
	statsFlag = flag.Bool("stats", false, "print statistics")
)

func usage() {
	fmt.Fprintf(os.Stderr, "Usage: %s [options] <input> [output]\n", os.Args[0])
	flag.PrintDefaults()
}

func timeSince(t time.Time) time.Duration {
	return time.Since(t)
}

func printStats(input []byte, elapsed time.Duration) {
	lines := bytes.Count(input, []byte{'\n'})
	words := len(bytes.Fields(input))
	chars := len(input)

	fmt.Fprintf(os.Stderr, "lines         = %d\n", lines)
	fmt.Fprintf(os.Stderr, "words         = %d\n", words)
	fmt.Fprintf(os.Stderr, "chars         = %d\n", chars)
	fmt.Fprintf(os.Stderr, "parse time    = %s\n", elapsed)
	fmt.Fprintf(os.Stderr, "chars/sec     = %d\n", chars/elapsed.Nanoseconds()*1e9)
}

func Parse(data, filename string) string {
	// Simple parser that extracts function definitions and their bodies
	var result []string

	// Remove comments
	data = removeComments(data)

	// Find all function definitions
	re := regexp.MustCompile(`(?m)^func\s+(\w+)\s*\((.*?)\)\s*(.*?)\s*\{`)
	matches := re.FindAllStringSubmatch(data, -1)

	for _, match := range matches {
		if len(match) >= 2 {
			funcName := match[1]
			params := match[2]
			returnType := match[3]

			// Find the function body
			start := re.FindStringIndex(data)[0]
			body := findFunctionBody(data, start)

			result = append(result, fmt.Sprintf("func %s(%s) %s { ... }", funcName, params, returnType))
		}
	}

	return strings.Join(result, "\n")
}

func removeComments(s string) string {
	// Remove single-line comments
	s = regexp.MustCompile(`//.*$`).ReplaceAllString(s, "")
	// Remove multi-line comments
	s = regexp.MustCompile(`/\*[\s\S]*?\*/`).ReplaceAllString(s, "")
	return s
}

func findFunctionBody(s string, start int) string {
	// Find matching brace
	braceCount := 0
	bodyStart := -1

	for i := start; i < len(s); i++ {
		if s[i] == '{' {
			if bodyStart == -1 {
				bodyStart = i
			}
			braceCount++
		} else if s[i] == '}' {
			braceCount--
			if braceCount == 0 && bodyStart != -1 {
				return s[bodyStart : i+1]
			}
		}
	}

	return ""
}
